import { z } from 'zod';

const userSchema = z.object({
  name: z.string().min(3, 'Ad ən az 3 simvol olmalıdır'),
  email: z.string().email('Düzgün e-poçt daxil edin'),
  age: z.number().min(18, 'Yaş 18-dən böyük olmalıdır')
});

function validateUser(data) {
  const result = userSchema.safeParse(data);
  if (!result.success) {
    return result.error.errors.map(e => e.message);
  }
  return 'Uğurlu!';
}

// Test
const errors = validateUser({ name: 'A', email: 'yanlis', age: 15 });
console.log(errors);

console.log('Zod ilə doğrulama yaradıldı');

import * as Yup from 'yup';

const userSchema = Yup.object().shape({
  name: Yup.string().min(3, 'Ad ən az 3 simvol').required('Ad tələb olunur'),
  email: Yup.string().email('Düzgün e-poçt').required('E-poçt tələb olunur'),
  password: Yup.string().min(6, 'Parol ən az 6 simvol').required()
});

async function validateUser(data) {
  try {
    await userSchema.validate(data, { abortEarly: false });
    return 'Uğurlu!';
  } catch (error) {
    return error.errors;
  }
}

console.log('Yup ilə doğrulama yaradıldı');

import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { zodResolver } from '@hookform/resolvers/zod';

const schema = z.object({
  email: z.string().email()
});

function LoginForm() {
  const { register, handleSubmit, formState: { errors } } = useForm({
    resolver: zodResolver(schema)
  });

  return (
    <form onSubmit={handleSubmit(data => console.log(data))}>
      <input {...register('email')} />
      {errors.email && <p>{errors.email.message}</p>}
      <button type="submit">Göndər</button>
    </form>
  );
}

console.log('React Hook Form + Zod yaradıldı');

